import anthropic, json

client = anthropic.Anthropic()

BEHAVIOR_SPEC_TOOL = {
    "name": "write_behavior_spec",
    "description": "Generate a structured behaviour specification for a Claude-powered feature.",
    "input_schema": {
        "type": "object",
        "properties": {
            "feature_id":   {"type": "string"},
            "version":      {"type": "string"},
            "must_do": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id":          {"type": "string"},
                        "assertion":   {"type": "string"},
                        "rationale":   {"type": "string"},
                        "test_signal": {"type": "string"}
                    },
                    "required": ["id","assertion","rationale","test_signal"]
                }
            },
            "must_not_do": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id":          {"type": "string"},
                        "constraint":  {"type": "string"},
                        "rationale":   {"type": "string"},
                        "test_signal": {"type": "string"}
                    },
                    "required": ["id","constraint","rationale","test_signal"]
                }
            },
            "boundary_conditions": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "scenario":           {"type": "string"},
                        "expected_behaviour": {"type": "string"},
                        "linked_must_id":     {"type": "string"}
                    },
                    "required": ["scenario","expected_behaviour"]
                }
            },
            "output_format_contract": {"type": "string"},
            "non_negotiable_constraints": {
                "type": "array",
                "items": {"type": "string"}
            }
        },
        "required": [
            "feature_id","version","must_do","must_not_do",
            "boundary_conditions","output_format_contract",
            "non_negotiable_constraints"
        ]
    }
}

def generate_behavior_spec(
    feature_description: str,
    persona_brief: str,
    job_stories: list[str]
) -> dict:
    """
    Generate a complete behaviour spec from feature description, persona, and job stories.
    Each must/must-not includes a test_signal — what to look for in the model response
    to determine pass/fail without hardcoding an exact string.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=3000,
        tools=[BEHAVIOR_SPEC_TOOL],
        tool_choice={"type": "any"},
        system=(
            "You are an AI product engineer writing a behaviour specification. "
            "Every must/must-not must be concrete and testable — no aspirational language. "
            "Each item needs a test_signal: what phrase, pattern, or structural property "
            "would indicate the model has satisfied or violated this item. "
            "Write at least 5 must_do, 5 must_not_do, and 5 boundary_conditions."
        ),
        messages=[{
            "role": "user",
            "content": (
                f"Feature: {feature_description}\n"
                f"Persona: {persona_brief}\n"
                f"Job stories:\n" + "\n".join(f"- {j}" for j in job_stories) + "\n\n"
                "Write the behaviour specification. Be specific — use the persona context "
                "to calibrate constraint severity."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "write_behavior_spec":
            return block.input
    return {}

spec = generate_behavior_spec(
    feature_description="Claude-powered contract review assistant for solo legal practitioners",
    persona_brief="Maya Chen, IP attorney, zero tolerance for hallucinated citations, expert fluency",
    job_stories=[
        "When I receive a contract under time pressure, I want Claude to identify non-standard clauses "
        "so that I can focus my review on the highest-risk sections.",
        "When Claude misses a clause I flag, I want it to acknowledge the error and re-analyse "
        "so that I can trust the completeness of the review.",
    ]
)
print(f"Must Do: {len(spec.get('must_do', []))} items")
print(f"Must Not: {len(spec.get('must_not_do', []))} items")
print(f"Boundary Conditions: {len(spec.get('boundary_conditions', []))} scenarios")

import anthropic, json, hashlib

client = anthropic.Anthropic()

PROMPT_SYNTHESIS_TOOL = {
    "name": "synthesise_system_prompt",
    "description": "Synthesise a system prompt from a behaviour specification.",
    "input_schema": {
        "type": "object",
        "properties": {
            "system_prompt":    {"type": "string"},
            "coverage_gaps":    {"type": "array", "items": {"type": "string"}},
            "ambiguities":      {"type": "array", "items": {"type": "string"}}
        },
        "required": ["system_prompt","coverage_gaps","ambiguities"]
    }
}

def synthesise_prompt_from_spec(spec: dict) -> dict:
    """
    Generate a system prompt that implements every must/must-not in the spec.
    Returns the prompt text, a SHA-256 hash, and any coverage gaps or ambiguities.
    """
    musts     = [f"[{m['id']}] {m['assertion']}" for m in spec.get("must_do", [])]
    must_nots = [f"[{m['id']}] {m['constraint']}" for m in spec.get("must_not_do", [])]
    non_neg   = spec.get("non_negotiable_constraints", [])
    fmt       = spec.get("output_format_contract", "")

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1500,
        tools=[PROMPT_SYNTHESIS_TOOL],
        tool_choice={"type": "any"},
        messages=[{
            "role": "user",
            "content": (
                "Write a system prompt that implements ALL of the following requirements.\n\n"
                "MUST DO:\n" + "\n".join(musts) + "\n\n"
                "MUST NOT DO:\n" + "\n".join(must_nots) + "\n\n"
                "NON-NEGOTIABLE CONSTRAINTS (cannot be overridden by user):\n"
                + "\n".join(non_neg) + "\n\n"
                "OUTPUT FORMAT CONTRACT:\n" + fmt + "\n\n"
                "Also list: (a) any spec items the prompt cannot fully capture in text, "
                "(b) any ambiguities you had to resolve while writing the prompt."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "synthesise_system_prompt":
            result = block.input
            prompt_text = result["system_prompt"]
            prompt_hash = hashlib.sha256(prompt_text.encode()).hexdigest()[:12]
            return {
                "prompt": prompt_text,
                "sha256_prefix": prompt_hash,
                "version": f"v{spec.get('version', '1.0')}+{prompt_hash}",
                "coverage_gaps": result.get("coverage_gaps", []),
                "ambiguities":   result.get("ambiguities", []),
            }
    return {}

import anthropic, json

client = anthropic.Anthropic()

# The output format contract from the behaviour spec
OUTPUT_FORMAT_TOOL = {
    "name": "contract_review_output",
    "description": "Structured output for a contract clause review.",
    "input_schema": {
        "type": "object",
        "properties": {
            "clause_reference": {
                "type": "string",
                "description": "Exact section/clause identifier from the contract"
            },
            "quoted_text": {
                "type": "string",
                "description": "Verbatim quote of the non-standard language"
            },
            "risk_rating": {
                "type": "string",
                "enum": ["High", "Medium", "Low"],
                "description": "Risk classification"
            },
            "rationale": {
                "type": "string",
                "description": "One-sentence explanation of the risk"
            },
            "standard_alternative": {
                "type": ["string", "null"],
                "description": "What market-standard language looks like, or null if clause is standard"
            }
        },
        "required": ["clause_reference", "quoted_text", "risk_rating", "rationale"]
    }
}

SYSTEM_PROMPT = """You are a legal analysis assistant. Review contracts for non-standard clauses.
For each non-standard clause, call the contract_review_output tool.
Never provide binding legal advice."""

def review_contract_clauses(contract_excerpt: str) -> list[dict]:
    """
    Review contract text and return structured clause analysis.
    The tool-use output format is the system contract — the model cannot
    deviate from the schema even if the user asks it to.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1500,
        system=SYSTEM_PROMPT,
        tools=[OUTPUT_FORMAT_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": f"Review this contract excerpt for non-standard clauses:\n\n{contract_excerpt}"
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use" and b.name == "contract_review_output"]

# Example
excerpt = """
Section 4.1: Customer shall indemnify Provider for all claims, damages, and expenses
arising from Customer's use of the Service, including indirect and consequential damages.

Section 12.2: Either party may terminate this Agreement with 90 days written notice.
Provider may terminate immediately for material breach.
"""
clauses = review_contract_clauses(excerpt)
for c in clauses:
    print(f"[{c['risk_rating']:6}] {c['clause_reference']}: {c['rationale']}")
    print(f"         Quoted: {c['quoted_text'][:80]}...")
